var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"말레볼제 홀, <color=#ffd34c>맥크레디 저택</color>\\nAM 01:30\\n학회 비정기 회동 중","JPN":"マーレボルジェホール、<color=#ffd34c>マクレディー家邸宅</color>\\nAM 01:30\\n学会の非定期会合中","ENG":"Malebolge Hall, <color=#ffd34c>MacCready Manor</color>\\n01:30 AM\\nIn the middle of Society's irregular meeting","TWN":"馬爾伯吉廳，<color=#ffd34c>麥克蕾蒂宅邸</color>\\n上午01:30\\n學會臨時動議中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"앞서 말씀드렸던 대로 학회가 추종하는 지식의 호수란 거대한 정보 집합체.","JPN":"先程お話ししたとおり、学会が追従している知識の湖とは巨大な情報の集合体。","ENG":"As I have mentioned before, The Lake of Knowledge that the Society follows is a massive collection of information.","TWN":"正如我之前說的那樣，學會推崇的知識湖水是個龐大的資訊集合體。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"즉, 정보에 굶주린 존재에 불과합니다.","JPN":"つまり、情報に飢えている存在に過ぎません。","ENG":"In other words, it is nothing but an existence that craves information.","TWN":"也就是說，它只不過是渴望資訊的存在。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"완전한 지식의 호수는 애초에 모순적인 표현입니다.","JPN":"完全な知識の湖というのは最初から矛盾している表現です。","ENG":"Having a \\"complete\\" Lake of Knowledge is a contradictory expression in and of itself.","TWN":"完整的知識湖水，從一開始就是矛盾的表述。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정보라는 것이 끊임없이 발생하는 이상, 호수는 필연적으로 불완전할 수밖에 없습니다.","JPN":"情報というものは常に生じるものである以上、湖は必然的に不完全であるしかありません。","ENG":"As long as information is constantly being created, the Lake will always be incomplete.","TWN":"只要資訊不斷產生，湖水必然不會完整。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 그 끝없는 허기를 만족시켜 주기 위해 학회는 숱한 범죄까지 저질러 왔죠.","JPN":"ですが、その底なきひもじさを満足させるために学会はあらゆる犯罪を犯してきました。","ENG":"However, the Society has committed heinous crimes just to satisfy this endless hunger.","TWN":"但是為了滿足這沒有盡頭的饑餓感，學會甚至犯下了很多罪行。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……저희 가문이 그 필두였다는 것 역시, 부정할 생각 없습니다.","JPN":"……私の家門がその筆頭であったということもまた、否定するつもりはありません。","ENG":"...As a member of the MacCready family, I do not deny my family spearheaded this movement.","TWN":"……我們家族就是帶頭的，這一點我也不想否認。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇기에 저는 이 자리에서 선언하겠습니다.","JPN":"ですので、今この場で私は宣言いたします。","ENG":"That is why I am here.","TWN":"所以我要在這裡宣佈。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"호수를 찾기 위해서란 명목으로 행해졌던 모든 비인륜적인 행위들….","JPN":"湖を探す名目で行われたすべての非道徳的な行為……","ENG":"To declare that all of the inhumane and evil practices committed in the name of finding this so-called Lake...","TWN":"以尋找湖水的名義犯下的所有不人道行為……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"특히 영지민의 차별 대우와 인신 공양을 비롯한 모든 악습들은 철저히 청산돼야 한다고.","JPN":"特に領地民の差別待遇や人身御供をはじめとするすべての悪習は徹底的に清算します。","ENG":"Especially the discrimination against the residents and human sacrifice shall be no more.","TWN":"尤其是差別對待領地居民，和活人祭祀在內的所有陋習，都要徹底廢除並清算。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이상입니다. 의견이 있다면 진솔하게 말씀해 주시길.","JPN":"以上です。ご意見がありましたら率直にお話しください。","ENG":"That is all. If you have any opinions, I am all ears.","TWN":"就是這些。有意見的話，請大家照實說出來。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"종교학부장, 아그네스입니다.","JPN":"宗教学部長のアグネスです。","ENG":"My name is Agnes, Dean of Religion.","TWN":"我是宗教學院院長，艾格妮絲。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"저희는 쇠락한 처지라 호수를 찾기는커녕 앞가림도 힘들어서 말이죠.","JPN":"私たちの学部は落ち目で、湖を探すどころか維持するのも精一杯でございまして。","ENG":"We are currently in decline, so we are struggling to keep our department running, let alone find the Lake.","TWN":"我們學院的處境很艱難，別說尋找湖水了，連維持下去都有困難。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님의 파격적인 구상을 지지할 수는 없지만, 반대할 이유도 없네요.","JPN":"副学会長の破格的な構想を支持することはできませんが、反対する理由もありません。","ENG":"Although we don't fully support Vice President, we also have no reason to be against it.","TWN":"雖然不能支援副學會長革新的想法，但我們也沒理由反對。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇군요. 의견 감사합니다.","JPN":"そうですか。ご意見、ありがとうございます。","ENG":"I see. Thank you for your input.","TWN":"這樣啊。謝謝你的意見。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"생물학부장, 하이드리히. 말씀 올리겠소.","JPN":"生物学部長のハイドリヒだ。私の考えを言おう。","ENG":"Dean of Biology, Heydrich. I would like to say a few words.","TWN":"我是生物學院院長，海德里希，我有話要說。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장의 방금 그 발언은 너무 비현실적이라 수용할 수 없군.","JPN":"副学会長の今の発言はあまりにも非現実的で受け入れられん。","ENG":"I cannot concur with your statement as it is too unrealistic.","TWN":"副學會長剛才的發言太不切實際了，所以我不能接受。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……어째서죠?","JPN":"……どうしてですか？","ENG":"...How so?","TWN":"……為什麼？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회는 먼 옛날부터 편견과 고정관념의 사슬을 풀고 다양한 시도를 해 왔소이다.","JPN":"学会は遠い昔から偏見と固定観念の鎖を解き、様々なことを試みて来た。","ENG":"The Society has made numerous attempts to break the bonds of prejudice and stereotypes since its inception.","TWN":"學會從很久以前開始就鬆開了偏見和固定觀念的鎖鏈，做了各種嘗試。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그건 전부, 호수에 도달하겠다는 일념 때문에 가능했지.","JPN":"それはすべて、湖にたどり着くという一念があったから可能だったのだ。","ENG":"All of this was possible due to a shared objective and determination to reach the Lake.","TWN":"那些全都是因為抵達湖水的堅定信念，才有了實現的可能。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자본, 권력, 기술. 학회가 축적한 힘은 모두 그 과정에서 나온 부산물이오.","JPN":"資本、権力、技術。学会が蓄積してきた力はすべて、その過程からできた副産物なのだ。","ENG":"Capital, authority, and technology. All of these are by-products resulting from the Society's accumulation of power.","TWN":"資本、權力、技術以及學會積累的力量，也都是這個過程中得到的附加價值。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그런데 이제 와서 호수를 포기하라니? 학회가 쌓아 온 모든 것을 부정할 수 있겠소?","JPN":"なのに、今更湖をあきらめろと？　学会が積み上げてきたすべてを否定できるのか？","ENG":"However, now you want us to give up the Lake? Are you willing to deny everything built by the Society?","TWN":"但事到如今，你說要放棄湖水？你怎麼能否認學會至今積累的一切？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지식의 호수는 곧 학회의 근간. 무지한 자들에게 휘둘리지 마시오.","JPN":"知識の湖はすなわち学会の根幹。無知な者たちに振り回されのはやめていただきたい。","ENG":"The Lake of Knowledge is the root of the Society. Please do not be swayed by the ignoramuses.","TWN":"知識湖水就是學會的根本，請不要受無知之人擺佈。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"휘둘린다는 표현에는 어폐가 있군요. 저는 그저 정론에 따를 뿐입니다.","JPN":"振り回されるという表現には語弊がありますわね。私はただ正論に従うまでです。","ENG":"I sense negativity in your expression of my \\"being swayed\\". However, I am just following the truth.","TWN":"擺佈這個說法有點不妥。我只是在遵循正確的觀點。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그 정론이란 것이 바로 무지한 자들의 잣대 아닌가?","JPN":"その正論というものが無知な者たちの物差しであろう。","ENG":"This truth you speak of, is it not the standard of the ignoramuses?","TWN":"你所謂的正確觀點，不就是無知之人的標準嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"인명을 중시한다면서 사람 목숨이 총알보다 싸게 먹히는 나라는 내버려 두고 있소.","JPN":"人命を重視すると言いながら、人の命が銃弾より安い国は放置している。","ENG":"We avoid countries where a life costs less than a bullet, despite their professed importance on human life.","TWN":"說要重視人命，卻放任子彈比人命還貴的國家不管。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지키지도 못할 말을 늘어 놓고는, 갖은 핑계를 대면서 이번만은 예외라고 떠들어대지.","JPN":"守ることもできない言葉を並べては、あらゆる言い訳を並べ立て今度だけは例外だと言う。","ENG":"They make empty promises and make excuses such as babbling about \\"exceptions\\".","TWN":"說出一些根本不能遵守的承諾，然後找各種藉口說這一次是意外。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"논지를 오도하지 마세요. 국제역학과 연구 영역은 서로 별개입니다.","JPN":"論旨を歪めないでください。国際力学と研究の領域は別ものです。","ENG":"Please do not misconstrue my point. International dynamics and academic disciplines are distinct.","TWN":"請不要轉移話題，國際歷史學和研究領域是兩回事。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"정녕 옳은 것에 예외 따위 존재하지 않소. 부학회장.","JPN":"真に正しいことに例外なぞ存在しないのだ。副学会長。","ENG":"Nevertheless, there are no \\"exceptions\\" to what is the truth, Vice President.","TWN":"真正正確的東西不存在例外，副學會長。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"윤리니 어쩌니 하는 얄팍한 잣대로 고삐를 거는 순간, 더 이상의 진보는 불가능하오.","JPN":"倫理だのなんだの、浅はかな物差しに当てはめるようになれば、それ以上の進歩はなくなるであろう。","ENG":"As soon as we bind ourselves with ethics or other arbitrary standards, further advancement becomes impossible.","TWN":"用倫理或者各種淺薄的標準約束自己的瞬間，我們就將停止進步的步伐。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"부정한 수단에 의지해서 얻은 결과는 아무 의미 없습니다! 왜 그걸 모르는 거죠?","JPN":"不正な手段に頼って手に入れた結果には何の意味もありませんわ！　どうしてそれをわからないのですか？","ENG":"Results mean nothing when they are achieved through dishonest means! Why do you not understand that?","TWN":"依靠不正當手段取得的成果沒有任何意義！你為什麼就不明白這個呢？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아, 저런…. 해서는 안 될 말을 해 버렸네.","JPN":"あらら……言っちゃいけないことを言っちゃったわね。","ENG":"Oh, my... She just said something she shouldn't have...","TWN":"哎呀……說了不該說的話呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아무래도 부학회장께선 현실에 대해 잘 모르시는가 보군.","JPN":"どうやら副学会長は現実についてよくご存じではないようだ。","ENG":"I believe our Vice President knows little about how the real world works.","TWN":"看來副學會長不是很了解現實世界。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"내가 경험한 바로는 그 반대였소.","JPN":"私の経験ではその反対であった。","ENG":"In my experience, it was the exact opposite.","TWN":"我所經歷的正好相反。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장님께 제출한 생물학부의 최신 연구 자료올시다.","JPN":"学会長に提出した生物学部の最新の研究結果だ。","ENG":"These are the Biology Department's most recent research reports submitted to the President.","TWN":"這是生物學院提交給學會長的最新研究資料。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부디 이 자리에서 검토해 주시겠소?","JPN":"どうかこの場で検討していただきたい。","ENG":"Will you please take a brief look at them now?","TWN":"請你務必在這裡看一下好嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};